#!/usr/bin/env python3

"""Scan Python test files and generate an Erlang include file.

Structure:
  - Single-class file -> CT group named after the class, containing test methods
  - Multi-class file  -> CT group named after the file, containing class subgroups

Usage: generate_python_tests.py <src_dir> <output_hrl>
"""

import os
import re
import sys
from collections import OrderedDict

BROKER_GROUPS = OrderedDict([
    ('tls', ['tls_connect_disconnect']),
    ('implicit_connect', ['implicit_connect']),
    ('main', [
        'parsing',
        'errors',
        'connect_disconnect',
        'ack',
        'amqp_headers',
        'queue_properties',
        'reliability',
        'transactions',
        'x_queue_name',
        'destinations',
        'redelivered',
        'topic_permissions',
        'unsubscribe',
        'x_queue_type_quorum',
        'x_queue_type_stream',
    ]),
])

CLASS_RE = re.compile(r'^class\s+(Test\w+)\s*[\(:]')
METHOD_RE = re.compile(r'^\s+def\s+(test_\w+)\s*\(')


def discover_file(src_dir, module):
    """Return OrderedDict: class_name -> [method_name, ...]"""
    classes = OrderedDict()
    path = os.path.join(src_dir, module + '.py')
    current_class = None
    with open(path) as f:
        for line in f:
            m = CLASS_RE.match(line)
            if m:
                current_class = m.group(1)
                if current_class not in classes:
                    classes[current_class] = []
                continue
            m = METHOD_RE.match(line)
            if m and current_class:
                classes[current_class].append(m.group(1))
    return classes


def short_class(class_name):
    return class_name.removeprefix('Test')


def erl_atom(s):
    return f"'{s}'"


def generate_hrl(src_dir, output_path):
    # Collect structure: broker_group -> [(group_name, is_multi, {class -> methods})]
    structure = OrderedDict()
    for bg, modules in BROKER_GROUPS.items():
        file_groups = []
        for mod in modules:
            classes = discover_file(src_dir, mod)
            multi = len(classes) > 1
            file_groups.append((mod, multi, classes))
        structure[bg] = file_groups

    all_funcs = []  # (erl_func_name, python_test_id)

    with open(output_path, 'w') as out:
        out.write("%% Generated by generate_python_tests.py — do not edit\n\n")

        # For each broker group, emit the subgroup list and class group definitions
        for bg, file_groups in structure.items():
            # Subgroup list for this broker group
            subgroups = []
            for mod, multi, classes in file_groups:
                if multi:
                    subgroups.append(mod)
                else:
                    cls_name = list(classes.keys())[0]
                    subgroups.append(short_class(cls_name))

            macro = bg.upper() + '_SUBGROUPS'
            out.write(f"-define({macro}, [\n")
            for i, sg in enumerate(subgroups):
                comma = ',' if i < len(subgroups) - 1 else ''
                out.write(f"    {{group, {erl_atom(sg)}}}{comma}\n")
            out.write("]).\n\n")

            # Group definitions
            for mod, multi, classes in file_groups:
                if multi:
                    # File group containing class subgroups
                    file_macro = mod.upper() + '_SUBGROUPS'
                    out.write(f"-define({file_macro}, [\n")
                    cls_list = list(classes.keys())
                    for i, cls in enumerate(cls_list):
                        sc = short_class(cls)
                        comma = ',' if i < len(cls_list) - 1 else ''
                        out.write(f"    {{group, {erl_atom(sc)}}}{comma}\n")
                    out.write("]).\n\n")

                    # Each class subgroup
                    for cls, methods in classes.items():
                        sc = short_class(cls)
                        cls_macro = sc.upper() + '_TESTS'
                        out.write(f"-define({cls_macro}, [\n")
                        for i, meth in enumerate(methods):
                            comma = ',' if i < len(methods) - 1 else ''
                            fn = f"{sc}.{meth}"
                            out.write(f"    {erl_atom(fn)}{comma}\n")
                        out.write("]).\n\n")
                        for meth in methods:
                            fn = f"{sc}.{meth}"
                            py_id = f"{mod}.{cls}.{meth}"
                            all_funcs.append((fn, py_id))
                else:
                    # Single class -> group directly contains tests
                    cls = list(classes.keys())[0]
                    sc = short_class(cls)
                    methods = classes[cls]
                    cls_macro = sc.upper() + '_TESTS'
                    out.write(f"-define({cls_macro}, [\n")
                    for i, meth in enumerate(methods):
                        comma = ',' if i < len(methods) - 1 else ''
                        fn = f"{sc}.{meth}"
                        out.write(f"    {erl_atom(fn)}{comma}\n")
                    out.write("]).\n\n")
                    for meth in methods:
                        fn = f"{sc}.{meth}"
                        py_id = f"{mod}.{cls}.{meth}"
                        all_funcs.append((fn, py_id))

        # CLASS_GROUPS macro — all group definitions for groups()
        out.write("-define(CLASS_GROUPS, [\n")
        all_group_defs = []
        for bg, file_groups in structure.items():
            for mod, multi, classes in file_groups:
                if multi:
                    all_group_defs.append(
                        f"    {{{erl_atom(mod)}, [], ?{mod.upper()}_SUBGROUPS}}")
                    for cls in classes:
                        sc = short_class(cls)
                        all_group_defs.append(
                            f"    {{{erl_atom(sc)}, [], ?{sc.upper()}_TESTS}}")
                else:
                    cls = list(classes.keys())[0]
                    sc = short_class(cls)
                    all_group_defs.append(
                        f"    {{{erl_atom(sc)}, [], ?{sc.upper()}_TESTS}}")
        out.write(',\n'.join(all_group_defs))
        out.write("\n]).\n\n")

        # Function definitions
        out.write("%% Test function definitions\n\n")
        seen = set()
        for fn, py_id in all_funcs:
            if fn not in seen:
                out.write(f"{erl_atom(fn)}(Config) -> "
                          f"run_one_test(Config, \"{py_id}\").\n")
                seen.add(fn)

    print(f"Generated {output_path}: {len(seen)} test functions")


if __name__ == '__main__':
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} <src_dir> <output_hrl>", file=sys.stderr)
        sys.exit(2)
    generate_hrl(sys.argv[1], sys.argv[2])
